import React from 'react'

const Post = props => {
    const {posts} = props;

    return ( 
        <div>
                { posts.map(post => (
                    <div key={post.id} className="card mt-4" style={{width: "100%"}}>                
                        <div className="card-body">
                                <h5 className="card-title">{post.title}</h5>
                                <p className="card-text">{post.body}</p>
                        </div>                  
                    </div>
                ))}
        </div>
     );
}
 
export default Post;