import React, { Component } from 'react'
import './NavStyles.css'
import Logo from "../../assets/aicdmb.png"

class Navbar extends Component {

    state={
        toggle: false
    }

    openFunc = () => {
        const {toggle} = this.state;
        this.setState({toggle: !toggle})
    };

    

    render() { 
        const {toggle} = this.state;
        return ( 
            <div>
                <div className="flex-container">
                    <ul className="uList">
                        <li className="logo"><img src={Logo} style={{height: "50px", width:"50px"}} alt="AICDMB_Logo"/></li>
                        <div id="nav-icon" className={toggle ? 'open' : null} onClick={this.openFunc}>
                            <span></span>
                            <span></span>
                            <span></span>
                            <span></span>
                        </div>
                        <div id="navLink" className="responsive" style={toggle ? {maxHeight: '500px'} : null}>
                            <li><a>Home</a></li>
                            <li><a>About</a></li>
                            <li><a>Contact</a></li>
                        </div>
                    </ul>
                </div>
            </div>
         );
    }
}
 
export default Navbar;